        _repo.SoftDelete(id);
        TempData["Flash"] = "User deleted.";
        return RedirectToAction(nameof(Index));
    }

    [Route("search")]
    [HttpGet]
    public IActionResult Search(string q)
    {
        var results = _repo.Search(q ?? "");
        return Json(results.Select(u => new { id = u.Id, label = u.Username + " — " + u.DisplayName }));
    }
}

